internal final class ETGLocalInputVATReportUIBuilder extends SrsReportDataContractUIBuilder
{
    ETGLocalInputVATReportContract contract;
    DialogField dialogFromDate;
    DialogField dialogToDate;
    DialogField vendAccount;

}

Method.Source:
public void build()
{
    contract            = this.dataContractObject() as ETGLocalInputVATReportContract;
    dialogFromDate      = this.addDialogField(methodStr(ETGLocalInputVATReportContract, parmFromDate), contract);
    dialogToDate        = this.addDialogField(methodStr(ETGLocalInputVATReportContract, parmToDate), contract);
    vendAccount         = this.addDialogField(methodStr(ETGLocalInputVATReportContract, parmVendAccount), contract);

}

public void postBuild()
{
    Dialog dialogobj = this.dialog();

    super();
    dialogFromDate  = this.bindInfo().getDialogField(contract, methodStr(ETGLocalInputVATReportContract, parmFromDate));
    dialogToDate    = this.bindInfo().getDialogField(contract, methodStr(ETGLocalInputVATReportContract, parmToDate));
    vendAccount     = this.bindInfo().getDialogField(contract, methodStr(ETGLocalInputVATReportContract, parmVendAccount));
}

public void postRun()
{
    ETGLocalInputVATReportContract etgLocalInputVATreportContract = this.dataContractObject();
}
